using System.ComponentModel;
using System.Net;
using System.Text;
using System.Text.RegularExpressions;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

const string modelId = "gpt-4o-mini-2024-07-18";

// --- Build the chat client via MEAI abstraction ---
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Define tools ---
var noteStore = new NoteStore();

var tools = new AITool[]
{
    AIFunctionFactory.Create(WebSearchTool.SearchAsync),
    AIFunctionFactory.Create(WebSearchTool.FetchPageAsync),
    AIFunctionFactory.Create(noteStore.SaveNote),
    AIFunctionFactory.Create(noteStore.GetNotes),
};

// --- Create the agent ---
var agent = new ChatClientAgent(chatClient, new ChatClientAgentOptions
{
    Name = "ResearchAgent",
    Description = "An agent that researches topics by searching the web and taking notes.",
    ChatOptions = new ChatOptions
    {
        Temperature = 0f,
        MaxOutputTokens = 2048,
        Tools = [.. tools],
    },
});
agent.Instructions = """
    You are a thorough research assistant. Follow this workflow:

    1. Use `search_web` to find information about the topic.
    2. Use `fetch_page` to read promising pages in full.
    3. Use `save_note` to record each key finding with a descriptive title.
    4. Repeat searches with different queries to cover multiple angles.
    5. When you have enough material, call `get_notes` to review everything.
    6. Produce a well-structured summary with sections, citing your sources.

    Be factual and concise. Prioritize recent, authoritative sources.
    """;

// --- Get the research topic ---
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();

if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\n🔍 Researching: {topic}\n");

// --- Run the agent (streaming) ---
var session = await agent.CreateSessionAsync();

await foreach (var update in agent.RunStreamingAsync(
    $"Research the following topic and provide a comprehensive summary: {topic}",
    session))
{
    if (!string.IsNullOrEmpty(update.Text))
    {
        Console.Write(update.Text);
    }
}

Console.WriteLine();

// ────────────────────────────────────────────
// Tool implementations
// ────────────────────────────────────────────

/// <summary>Tools for searching the web and fetching page content.</summary>
static partial class WebSearchTool
{
    private static readonly HttpClient Http = CreateHttpClient();

    private static HttpClient CreateHttpClient()
    {
        var client = new HttpClient { Timeout = TimeSpan.FromSeconds(15) };
        client.DefaultRequestHeaders.UserAgent.ParseAdd(
            "ResearchAgent/1.0 (Console; .NET 10)");
        return client;
    }

    [Description("Searches the web for a query and returns a list of result titles, URLs, and snippets.")]
    public static async Task<string> SearchAsync(
        [Description("The search query")] string query)
    {
        try
        {
            var url = $"https://html.duckduckgo.com/html/?q={Uri.EscapeDataString(query)}";
            var html = await Http.GetStringAsync(url);

            var results = new List<SearchResult>();
            var resultPattern = ResultRegex();

            foreach (Match m in resultPattern.Matches(html))
            {
                if (results.Count >= 5)
                    break;

                var resultHtml = m.Value;

                var hrefMatch = HrefRegex().Match(resultHtml);
                var titleMatch = TitleRegex().Match(resultHtml);
                var snippetMatch = SnippetRegex().Match(resultHtml);

                var href = hrefMatch.Success
                    ? WebUtility.HtmlDecode(hrefMatch.Groups[1].Value)
                    : "";
                var title = titleMatch.Success
                    ? StripHtml(WebUtility.HtmlDecode(titleMatch.Groups[1].Value))
                    : "";
                var snippet = snippetMatch.Success
                    ? StripHtml(WebUtility.HtmlDecode(snippetMatch.Groups[1].Value))
                    : "";

                // DuckDuckGo redirects through uddg param
                if (href.Contains("uddg="))
                {
                    var uddg = Regex.Match(href, @"uddg=([^&]+)");
                    if (uddg.Success)
                        href = Uri.UnescapeDataString(uddg.Groups[1].Value);
                }

                if (!string.IsNullOrWhiteSpace(title))
                    results.Add(new(title.Trim(), href.Trim(), snippet.Trim()));
            }

            if (results.Count == 0)
                return "No search results found. Try a different query.";

            var sb = new StringBuilder();
            for (int i = 0; i < results.Count; i++)
            {
                var r = results[i];
                sb.AppendLine($"[{i + 1}] {r.Title}");
                sb.AppendLine($"    URL: {r.Url}");
                sb.AppendLine($"    {r.Snippet}");
                sb.AppendLine();
            }

            return sb.ToString();
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    [Description("Fetches the text content of a web page given its URL. Returns the first ~3000 characters of readable text.")]
    public static async Task<string> FetchPageAsync(
        [Description("The full URL of the page to fetch")] string url)
    {
        try
        {
            var html = await Http.GetStringAsync(url);

            // Strip scripts, styles, and HTML tags to get readable text
            var text = Regex.Replace(html, @"<script[^>]*>[\s\S]*?</script>", " ", RegexOptions.IgnoreCase);
            text = Regex.Replace(text, @"<style[^>]*>[\s\S]*?</style>", " ", RegexOptions.IgnoreCase);
            text = Regex.Replace(text, @"<[^>]+>", " ");
            text = WebUtility.HtmlDecode(text);
            text = Regex.Replace(text, @"\s+", " ").Trim();

            const int maxLength = 3000;
            if (text.Length > maxLength)
                text = text[..maxLength] + "... [truncated]";

            return string.IsNullOrWhiteSpace(text)
                ? "Page returned no readable text."
                : text;
        }
        catch (Exception ex)
        {
            return $"Failed to fetch page: {ex.Message}";
        }
    }

    private static string StripHtml(string html) =>
        Regex.Replace(html, @"<[^>]+>", "").Trim();

    [GeneratedRegex(@"<div[^>]*class=""[^""]*result\b[^""]*""[^>]*>[\s\S]*?(?=<div[^>]*class=""[^""]*result\b|$)")]
    private static partial Regex ResultRegex();

    [GeneratedRegex(@"href=""([^""]+)""")]
    private static partial Regex HrefRegex();

    [GeneratedRegex(@"class=""[^""]*result__a[^""]*""[^>]*>([\s\S]*?)</a>")]
    private static partial Regex TitleRegex();

    [GeneratedRegex(@"class=""[^""]*result__snippet[^""]*""[^>]*>([\s\S]*?)</")]
    private static partial Regex SnippetRegex();

    private record SearchResult(string Title, string Url, string Snippet);
}

/// <summary>In-memory note-taking tool for the research agent.</summary>
sealed class NoteStore
{
    private readonly List<(string Title, string Content)> _notes = [];

    [Description("Saves a research note. Use a descriptive title and include the source URL when available.")]
    public string SaveNote(
        [Description("Short descriptive title for the note")] string title,
        [Description("The note content (facts, quotes, analysis)")] string content)
    {
        _notes.Add((title, content));
        return $"Note #{_notes.Count} saved: \"{title}\"";
    }

    [Description("Retrieves all saved research notes to review before writing the summary.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        var sb = new StringBuilder();
        for (int i = 0; i < _notes.Count; i++)
        {
            sb.AppendLine($"--- Note #{i + 1}: {_notes[i].Title} ---");
            sb.AppendLine(_notes[i].Content);
            sb.AppendLine();
        }

        return sb.ToString();
    }
}

