using System.ComponentModel;
using System.Net;
using System.Text;
using System.Text.RegularExpressions;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

const string modelId = "gpt-4o-mini-2024-07-18";

// --- Build the chat client via MEAI abstraction ---
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Define tools ---
var noteStore = new NoteStore();

var tools = new AITool[]
{
    AIFunctionFactory.Create(WebSearchTool.SearchAsync),
    AIFunctionFactory.Create(WebSearchTool.FetchPageAsync),
    AIFunctionFactory.Create(noteStore.SaveNote),
    AIFunctionFactory.Create(noteStore.GetNotes),
};

// --- Create the agent ---
var agent = new ChatClientAgent(chatClient, new ChatClientAgentOptions
{
    Name = "ResearchAgent",
    Description = "An agent that researches topics by searching the web and taking notes.",
    ChatOptions = new ChatOptions
    {
        Temperature = 0f,
        MaxOutputTokens = 2048,
        Tools = [.. tools],
    },
});
agent.Instructions = """
    You are a thorough research assistant. Follow this workflow:

    1. Use `search_web` to find information about the topic.
    2. Use `fetch_page` to read promising pages in full.
    3. Use `save_note` to record each key finding with a descriptive title.
    4. Repeat searches with different queries to cover multiple angles.
    5. When you have enough material, call `get_notes` to review everything.
    6. Produce a well-structured summary with sections, citing your sources.

    Be factual and concise. Prioritize recent, authoritative sources.
    """;

// --- Get the research topic ---
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();

if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\n🔍 Researching: {topic}\n");

// --- Run the agent (streaming) ---
var session = await agent.CreateSessionAsync();

await foreach (var update in agent.RunStreamingAsync(
    $"Research the following topic and provide a comprehensive summary: {topic}",
    session))
{
    if (!string.IsNullOrEmpty(update.Text))
    {
        Console.Write(update.Text);
    }
}

Console.WriteLine();

